external_knowledge:
- 'online servers' refers to servers with a server status of 'online'; 
- 'performance metrics' include CPU usage, query performance, and disk usage; 
- 'total CPU usage' refers to the sum of CPU usage for each server; 
- 'total query performance' is the sum of query performance for each database; 
- 'maximum database disk usage' and 'maximum server disk usage' refer to the maximum disk usage for databases and servers, respectively.

sql:
SELECT db_owner
FROM databases
WHERE db_size = (SELECT MAX(db_size) FROM databases);

SELECT 
  (SELECT SUM(db_size) FROM databases) AS total_database_size,
  (SELECT SUM(file_size) FROM files) AS total_memory_used;

SELECT database_name
FROM databases
WHERE db_growth_rate = (SELECT MAX(db_growth_rate) FROM databases);

SELECT UPPER(database_name) AS highest_growth_rate_db
FROM databases
WHERE db_growth_rate = (
  SELECT MAX(db_growth_rate)
  FROM databases
);
